const BASE = 'https://plm.uni-paderborn.de';
msg.baseUrl = BASE;
msg.url = BASE + '/api/v1/collection/part/' + msg.payload;
msg.headers = {'Accept':'application/json'};
return msg;

const targets = msg.payload.targets || [];
node.warn('BOM: ' + targets.length + ' Items gefunden');

if (targets.length === 0) {
    msg.topic = 'bom';
