    msg.parts = {id: 0, count: 1, index: 0};
    return msg;
}

flow.set('bomTotal', targets.length);
flow.set('bomCollected', []);

const msgs = targets.map((u, i) => ({
    url: typeof u === 'string' ? u : u['@id'],
    headers: {'Accept': 'application/json'},
    topic: 'bom_item',
    parts: {id: i, count: targets.length, index: i},
    partData: msg.partData,
    baseUrl: msg.baseUrl
}));
return [msgs];

const t=msg.payload.targets||[];
node.warn('Docs: '+t.length+' gefunden');
if(t.length===0){
  msg.topic='doc';
  msg.payload={docData:null,cadBuffer:null,previewBuffer:null};
  return msg;
}
msg.url=typeof t[0]==='string'?t[0]:t[0]['@id'];
msg.headers={'Accept':'application/json'};
return msg;

const docObj = msg.payload;
if (!docObj || !docObj['@id']) {
    node.error('Keine Dokumenten-Metadaten erhalten');
    return null;
}

msg.docMetadata = {
    fileId:             docObj['z_nummer'] || '',
    fileVersion:        docObj['src_index'] || docObj['z_index'] || '1',
    title:              docObj['titel'] || docObj['benennung'] || 'Modell',
    fileClassification: docObj['erzeug_system'] || 'CAD-Modell',
    consumingApp:       docObj['erzeug_system'] || 'SolidWorks',
    uiLink:             docObj['system:ui_link'] || ''
};

msg.url = docObj['@id'] + '/files?data=complete';
msg.headers = { 'Accept': 'application/json' };
return msg;

const fileCollection = msg.payload;
const targets = fileCollection.targets || [];
node.warn('Anzahl gefundener Target-Dateien: ' + targets.length);

if (targets.length === 0) {
    msg.topic = 'doc';
    msg.payload = { docData: msg.docMetadata, cadBuffer: null, previewBuffer: null };
    return [null, msg];
}

const t0 = targets[0];
msg.cadUrl = typeof t0 === 'string' ? t0 : (t0['@id'] || null);
msg.cadName = typeof t0 === 'object' ? (t0['cdbf_name'] || 'model.sldasm') : 'model.sldasm';

const t1 = targets[1];
msg.previewUrl = t1 ? (typeof t1 === 'string' ? t1 : (t1['@id'] || null)) : null;
msg.previewName = (t1 && typeof t1 === 'object') ? (t1['cdbf_name'] || 'preview.jpg') : 'preview.jpg';

msg.url = msg.cadUrl;
msg.headers = { 'Accept': '*/*' };
return msg;

if (msg.statusCode === 200 && msg.payload) {
    msg.cadBuffer = msg.payload;
} else {
    node.warn('CAD Download unvollständig: ' + msg.statusCode);
    msg.cadBuffer = null;
}

if (msg.previewUrl) {
    msg.url = msg.previewUrl;
    msg.headers = { 'Accept': '*/*' };
    return msg;
}

msg.previewBuffer = null;
msg.topic = 'doc';
msg.payload = {
    docData: msg.docMetadata,
    cadBuffer: msg.cadBuffer,
    cadName: msg.cadName,
    previewBuffer: null,
    previewName: msg.previewName
};
return msg;

if (msg.statusCode === 200 && msg.payload) {
