const FILE_BIN    = 'C:/tmp/cim_cad_file.bin';
const PREVIEW_BIN = 'C:/tmp/cim_preview_file.bin';

const fs   = global.get('fs');
const path = global.get('path');

try { if(!fs.existsSync('C:/tmp')) fs.mkdirSync('C:/tmp',{recursive:true}); } catch(e){}

const cadBuf = docRes.cadBuffer;
if(cadBuf && cadBuf.length > 0){
  try { fs.writeFileSync(FILE_BIN, cadBuf); node.warn('CAD-Binary geschrieben: ' + cadBuf.length + ' bytes'); }
  catch(e) { node.warn('CAD schreiben fehlgeschlagen: ' + e.message); }
}

