if(prevBuf && prevBuf.length > 0){
  try { fs.writeFileSync(PREVIEW_BIN, prevBuf); node.warn('Preview-Binary geschrieben: ' + prevBuf.length + ' bytes'); }
  catch(e) { node.warn('Preview schreiben fehlgeschlagen: ' + e.message); }
}

let maxBomCsv = '';
try {
    const csvPath = BASE_PATH.replace(/\//g,'\\') + '\\aasx\\files\\Produktstruktur_MaxBOM_TRACEpen_Kugelschreiber.CSV';
    if (fs.existsSync(csvPath)) {
        maxBomCsv = fs.readFileSync(csvPath, 'latin1');
        node.warn('MaxBOM CSV geladen: ' + csvPath);
    }
} catch(e) { node.warn('MaxBOM CSV nicht geladen: ' + e.message); }

const partNameSafe = (part && part.name) ? part.name : '';
const templateXmlPath = partNameSafe
    ? OUTPUT_PATH + '/' + partNameSafe + '/aasx/' + partNameSafe + '/' + partNameSafe + '.aas.xml'
    : '';
node.warn('Template XML Pfad: ' + templateXmlPath);

const data = {
  part: part,
  bomItems: bom,
  docData: docRes.docData||null,
  fileName: docRes.fileName||"model.sldasm",
  previewName: docRes.previewName||"preview.jpg",
  basePath: BASE_PATH,
  outputPath: OUTPUT_PATH,
  cadBinPath: (cadBuf&&cadBuf.length>0) ? FILE_BIN : null,
  previewBinPath: (prevBuf&&prevBuf.length>0) ? PREVIEW_BIN : null,
  maxBomCsv: maxBomCsv,
  templateXmlPath: templateXmlPath,
