try{
  fs.writeFileSync(DATA_JSON, JSON.stringify(data,null,2),'utf8');
  node.warn('JSON geschrieben: '+DATA_JSON);
}catch(e){
  node.error('JSON schreiben fehlgeschlagen: '+e.message);
  return null;
}

msg.pythonScript = PYTHON_SCRIPT;
msg.dataJson     = DATA_JSON;
msg.outputPath   = OUTPUT_PATH;
msg.payload      = 'python "' + PYTHON_SCRIPT + '" "' + DATA_JSON + '"';
node.warn('Starte Python: '+msg.payload);
return msg;

const out = typeof msg.payload==='string' ? msg.payload : JSON.stringify(msg.payload);
if(out && out.trim()) node.warn('Python output: '+out.substring(0,2000));
msg.payload = {
  status: msg.rc===0||out.includes('FERTIG') ? 'OK' : 'CHECK',
  pythonOutput: out,
  outputPath: msg.outputPath||'?',
};
return msg;

const p = msg.payload;
if(msg.statusCode!==200){node.error('Part HTTP '+msg.statusCode);return null;}
const rel = (p['system:relships']&&p['system:relships']['relships'])||{};
msg.partData = {
  name:             p['benennung']||null,
  articleNumber:    p['teilenummer']||null,
  erpNumber:        p['materialnr_erp']||null,
  status:           p['joined_status_name']||null,
  navigationId:     p['system:navigation_id']||null,
  uiLink:           p['system:ui_link']||null,
  unit:             p['mengeneinheit_name']||p['mengeneinheit']||null,
