  techdaten:        p['techdaten']||null
};
msg.relBomUrl  = rel['BOM']||null;
msg.relDocsUrl = rel['Documents']||null;
node.warn('Part OK: '+msg.partData.name);
return msg;

const partData = msg.partData;
if (!partData || !partData.techdaten) {
    msg.partWeight = 0.0;
    msg.partMaterialName = "Kein Material definiert";
    return [null, msg];
}
try {
    const parts = partData.techdaten.split(",");
    const materialId = parts[0].trim();
    const weightKg = parseFloat(parts[1].trim());
    msg.partWeight = weightKg;
    msg.partMaterialId = materialId;
    msg.url = `https://plm.uni-paderborn.de/api/v1/collection/material/${materialId}`;
    return [msg, null];
} catch (e) {
    node.error("Fehler beim Parsen der Haupt-Techdaten: " + e.message, msg);
    msg.partWeight = 0.0;
    msg.partMaterialName = "Formatfehler Techdaten";
    return [null, msg];
}

const materialData = msg.payload;
if (msg.statusCode !== 200 || !materialData) {
    node.error("Haupt-Material HTTP Fehler " + msg.statusCode);
    msg.partMaterialName = "API Fehler";
} else {
    msg.partMaterialName = materialData.name || "Unbenanntes Material";
}
return msg;

msg.partData.weight = msg.partWeight;
